import re; filepath = 'backend/data_fetcher.py'; f = open(filepath, 'r', encoding='utf-8'); content = f.read(); f.close(); content = content.replace('import requests\n', ''); blocks = re.findall(r'\s+session = requests\.Session\(\).*?t = yf\.Ticker\(ticker, session=session\)', content, flags=re.DOTALL); [content := content.replace(b, b[:len(b)-len(b.lstrip())] + 't = yf.Ticker(ticker)') for b in blocks]; f = open(filepath, 'w', encoding='utf-8', newline='\r\n'); f.write(content); f.close()
